globals.css:
/* Generated by Lowdefy build */

/* Layer order — locks cascade priority before Tailwind declares its own layers */
@layer theme, base, antd, components, utilities;

@import "tailwindcss";
@import "@lowdefy/layout/grid.css";

/* Content sources for Tailwind JIT — block JS content collected at build time */
@source "../lowdefy-build/tailwind/*.html";

/* Imported CSS file — when this changes, PostCSS re-runs and Tailwind re-scans @source */
@import "./tailwind-candidates.css";

/* Themed scrollbars — opts out of the browser default that clashes on dark surfaces,
   especially on Windows/Linux where scrollbars are always visible and native-chrome.
   Colors use antd CSS custom properties so they auto-swap with dark/light mode. */
@layer base {
  * {
    scrollbar-width: thin;
    scrollbar-color: var(--ant-color-border-secondary, rgba(0, 0, 0, 0.15)) transparent;
  }
  *::-webkit-scrollbar {
    width: 10px;
    height: 10px;
  }
  *::-webkit-scrollbar-track {
    background: transparent;
  }
  *::-webkit-scrollbar-thumb {
    background-color: var(--ant-color-border-secondary, rgba(0, 0, 0, 0.15));
    background-clip: padding-box;
    border: 2px solid transparent;
    border-radius: 10px;
  }
  *::-webkit-scrollbar-thumb:hover {
    background-color: var(--ant-color-text-tertiary, rgba(0, 0, 0, 0.45));
  }
  *::-webkit-scrollbar-corner {
    background: transparent;
  }
}

/* Antd-to-Tailwind theme bridge — extends default Tailwind theme with antd design tokens */
@theme inline {
  --color-primary: var(--ant-color-primary);
  --color-primary-hover: var(--ant-color-primary-hover);
  --color-primary-active: var(--ant-color-primary-active);
  --color-primary-bg: var(--ant-color-primary-bg);
  --color-success: var(--ant-color-success);
  --color-warning: var(--ant-color-warning);
  --color-error: var(--ant-color-error);
  --color-info: var(--ant-color-info);
  --color-text-primary: var(--ant-color-text);
  --color-text-secondary: var(--ant-color-text-secondary);
  --color-bg-container: var(--ant-color-bg-container);
  --color-bg-layout: var(--ant-color-bg-layout);
  --color-border: var(--ant-color-border);
  --radius-DEFAULT: var(--ant-border-radius);
  --radius-sm: var(--ant-border-radius-sm);
  --radius-lg: var(--ant-border-radius-lg);
  --font-size-DEFAULT: var(--ant-font-size);
  --font-size-sm: var(--ant-font-size-sm);
  --font-size-lg: var(--ant-font-size-lg);
  --font-family-sans: var(--ant-font-family);
}

